import * as THREE from 'three';

import {
  requestCameraCloseUp,
  restoreCameraCloseUp,
  type CameraCloseUpOptions,
  type CameraCloseUpTarget,
} from './closeUp';
import { useGaesupStore } from '../stores/gaesupStore';
import { useSceneStore } from '../scene/stores/sceneStore';
import { useCharacterStore } from '../character/stores/characterStore';
import { useDialogStore } from '../dialog/stores/dialogStore';
import type { DialogContext, DialogTreeId } from '../dialog/types';
import type { FaceStyle, OutfitSlot } from '../character/types';

type CameraCinematicFocusBeat = {
  target: CameraCloseUpTarget;
  durationMs?: number;
} & CameraCloseUpOptions;

export type CameraCinematicBeat =
  | ({ kind: 'closeUp' } & CameraCinematicFocusBeat)
  | ({ kind: 'lookAt' } & CameraCinematicFocusBeat)
  | ({
      kind: 'dolly';
      target: CameraCloseUpTarget;
      fromDistance?: number;
      toDistance: number;
      durationMs?: number;
    } & Omit<CameraCloseUpOptions, 'focusDistance'>)
  | ({
      kind: 'orbit';
      target: CameraCloseUpTarget;
      radius: number;
      angleDeg?: number;
      height?: number;
      durationMs?: number;
    } & Omit<CameraCloseUpOptions, 'focusDistance'>)
  | {
      kind: 'shake';
      intensity?: number;
      durationMs?: number;
    }
  | {
      kind: 'fade';
      color?: string;
      direction?: 'in' | 'out' | 'inOut';
      durationMs?: number;
    }
  | {
      kind: 'dialog';
      treeId: DialogTreeId;
      context?: DialogContext;
      durationMs?: number;
    }
  | {
      kind: 'expression';
      face: FaceStyle;
      durationMs?: number;
    }
  | {
      kind: 'equip';
      slot: OutfitSlot;
      itemId: string | null;
      durationMs?: number;
    }
  | {
      kind: 'teleport';
      position: CameraCloseUpTarget;
      durationMs?: number;
    }
  | {
      kind: 'animation';
      name: string;
      durationMs?: number;
    }
  | {
      kind: 'npcMove';
      npcId: string;
      position: CameraCloseUpTarget;
      durationMs?: number;
    }
  | {
      kind: 'event';
      name: string;
      payload?: unknown;
      durationMs?: number;
    }
  | {
      kind: 'wait';
      durationMs: number;
    }
  | {
      kind: 'restore';
      durationMs?: number;
    };

export type CameraCinematicOptions = {
  restoreOnComplete?: boolean;
  onTeleport?: (position: THREE.Vector3) => void;
  onAnimation?: (name: string) => void;
  onNpcMove?: (npcId: string, position: THREE.Vector3) => void;
  onEvent?: (name: string, payload?: unknown) => void;
};

export type CameraCinematicPlayback = {
  cancel: () => void;
  finished: Promise<void>;
};

function delay(ms: number, isCancelled: () => boolean): Promise<void> {
  if (ms <= 0 || isCancelled()) return Promise.resolve();

  return new Promise((resolve) => {
    const timeout = globalThis.setTimeout(resolve, ms);
    if (isCancelled()) {
      globalThis.clearTimeout(timeout);
      resolve();
    }
  });
}

function toVector3(target: CameraCloseUpTarget): THREE.Vector3 {
  if (target instanceof THREE.Vector3) return target.clone();
  if (Array.isArray(target)) return new THREE.Vector3(target[0], target[1], target[2]);
  return new THREE.Vector3(target.x, target.y, target.z);
}

function playFocusBeat(
  beat: CameraCinematicFocusBeat,
  rememberPrevious: boolean,
  defaultDurationMs: number,
): number {
  const {
    target,
    durationMs = defaultDurationMs,
    focusDistance,
    focusLerpSpeed,
    fov,
    enableCollision,
  } = beat;
  requestCameraCloseUp(target, {
    rememberPrevious,
    ...(focusDistance !== undefined ? { focusDistance } : {}),
    ...(focusLerpSpeed !== undefined ? { focusLerpSpeed } : {}),
    ...(fov !== undefined ? { fov } : {}),
    ...(enableCollision !== undefined ? { enableCollision } : {}),
  });
  return durationMs;
}

async function playFadeBeat(
  beat: Extract<CameraCinematicBeat, { kind: 'fade' }>,
  isCancelled: () => boolean,
): Promise<void> {
  const durationMs = beat.durationMs ?? 360;
  const direction = beat.direction ?? 'inOut';
  const color = beat.color ?? '#000000';
  const store = useSceneStore.getState();

  if (direction === 'out' || direction === 'inOut') {
    store.setTransition({ active: true, color, progress: 1 });
    await delay(durationMs, isCancelled);
  }

  if (direction === 'in' || direction === 'inOut') {
    store.setTransition({ active: true, color, progress: 0 });
    await delay(durationMs, isCancelled);
    store.setTransition({ active: false, color, progress: 0 });
  }
}

async function playShakeBeat(
  beat: Extract<CameraCinematicBeat, { kind: 'shake' }>,
  isCancelled: () => boolean,
): Promise<void> {
  const store = useGaesupStore.getState();
  const previousOffset = store.cameraOption.offset?.clone();
  const intensity = beat.intensity ?? 0.35;

  store.setCameraOption({
    offset: store.cameraOption.offset?.clone().addScalar(intensity) ?? toVector3([intensity, 0, -intensity]),
  });
  await delay(beat.durationMs ?? 220, isCancelled);
  if (previousOffset) {
    store.setCameraOption({ offset: previousOffset });
  } else {
    const { offset, ...nextCameraOption } = useGaesupStore.getState().cameraOption;
    void offset;
    useGaesupStore.getState().replaceCameraOption(nextCameraOption);
  }
}

export function playCameraCinematic(
  beats: CameraCinematicBeat[],
  options: CameraCinematicOptions = {},
): CameraCinematicPlayback {
  let cancelled = false;
  const restoreOnComplete = options.restoreOnComplete ?? true;

  const finished = (async () => {
    let rememberedPreviousCamera = false;
    try {
      for (let index = 0; index < beats.length; index += 1) {
        if (cancelled) break;
        const beat = beats[index];
        if (!beat) continue;

        if (beat.kind === 'closeUp' || beat.kind === 'lookAt') {
          const durationMs = playFocusBeat(beat, !rememberedPreviousCamera, 900);
          rememberedPreviousCamera = true;
          await delay(durationMs, () => cancelled);
          continue;
        }

        if (beat.kind === 'dolly') {
          const { fromDistance, toDistance, ...rest } = beat;
          if (fromDistance !== undefined) {
            playFocusBeat({ ...rest, focusDistance: fromDistance, durationMs: 16 }, !rememberedPreviousCamera, 16);
            rememberedPreviousCamera = true;
            await delay(16, () => cancelled);
          }
          const durationMs = playFocusBeat({ ...rest, focusDistance: toDistance }, !rememberedPreviousCamera, 700);
          rememberedPreviousCamera = true;
          await delay(durationMs, () => cancelled);
          continue;
        }

        if (beat.kind === 'orbit') {
          const center = toVector3(beat.target);
          const height = beat.height ?? 0;
          const angle = ((beat.angleDeg ?? 0) * Math.PI) / 180;
          const target = {
            x: center.x + Math.cos(angle) * beat.radius,
            y: center.y + height,
            z: center.z + Math.sin(angle) * beat.radius,
          };
          const orbitBeat: CameraCinematicFocusBeat = {
            target,
            focusDistance: beat.radius,
            ...(beat.durationMs !== undefined ? { durationMs: beat.durationMs } : {}),
            ...(beat.focusLerpSpeed !== undefined ? { focusLerpSpeed: beat.focusLerpSpeed } : {}),
            ...(beat.fov !== undefined ? { fov: beat.fov } : {}),
            ...(beat.enableCollision !== undefined ? { enableCollision: beat.enableCollision } : {}),
          };
          const durationMs = playFocusBeat(orbitBeat, !rememberedPreviousCamera, 700);
          rememberedPreviousCamera = true;
          await delay(durationMs, () => cancelled);
          continue;
        }

        if (beat.kind === 'shake') {
          await playShakeBeat(beat, () => cancelled);
          continue;
        }

        if (beat.kind === 'fade') {
          await playFadeBeat(beat, () => cancelled);
          continue;
        }

        if (beat.kind === 'dialog') {
          useDialogStore.getState().start(beat.treeId, beat.context ? { context: beat.context } : undefined);
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'expression') {
          useCharacterStore.getState().setFace(beat.face);
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'equip') {
          useCharacterStore.getState().equipOutfit(beat.slot, beat.itemId);
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'teleport') {
          options.onTeleport?.(toVector3(beat.position));
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'animation') {
          options.onAnimation?.(beat.name);
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'npcMove') {
          options.onNpcMove?.(beat.npcId, toVector3(beat.position));
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'event') {
          options.onEvent?.(beat.name, beat.payload);
          await delay(beat.durationMs ?? 0, () => cancelled);
          continue;
        }

        if (beat.kind === 'wait') {
          await delay(beat.durationMs, () => cancelled);
          continue;
        }

        restoreCameraCloseUp();
        await delay(beat.durationMs ?? 0, () => cancelled);
      }
    } finally {
      if (restoreOnComplete || cancelled) {
        restoreCameraCloseUp();
      }
    }
  })();

  return {
    cancel: () => {
      cancelled = true;
      restoreCameraCloseUp();
    },
    finished,
  };
}
